	('421f9b0d-5db0-47b3-8d48-203b9213dc00', 'SaaS管理会社', NULL, NULL, NULL, NULL, '2026-04-11 01:29:06.53215+09', 'pro', 1000, NULL, NULL, NULL, NULL, '2026-03-02 20:53:47.009+09', NULL),
	('8f788279-3f9e-491f-984d-91439b582ac8', 'sample', NULL, 0, 10, NULL, '2026-03-06 20:12:22.153969+09', 'free', 30, 'ABCエンジニアリング', 'ABCエンジニアリングは、ICT・環境・省エネに関連する多彩なソリューションを通じて、企業や施設のオフィス環境の改善、ビルのスマート化、環境経営の向上を支援します。オフィスソリューションでは、企業の生産性を向上させる未来的なオフィス環境を実現し、スマートソリューションではICTを駆使してエネルギー管理や再生可能エネルギーの導入をサポートします。環境コンサルティングでは、カーボンニュートラルへの取り組みを促進します。', '「地球にやさしいエンジニアリング企業」として、持続可能な社会に貢献することを目指しています。', '技術と情熱が融合した職場環境で、未来のインフラを共に創り上げる仲間を募り、持続的な社会に貢献する活動を奨励しています。', '2026-03-06 20:18:00.833+09', NULL);
