	('3a5034ba-06dc-4157-b1bd-351d4bc5c01f', '35c69c7f-6580-4250-a125-d15c28ead6b2', '従業員の登録', NULL, '基本設定', '受検対象となる従業員情報を一括インポートや個別編集で管理。
